// Szakma-kódprefix (a belépési kód olvashatóságához)
function tradePrefix(trade) {
  const map = {
    "Villanyszerelő": "VILL", "Nyílászárós": "NYIL", "Vízvezeték-szerelő": "VIZ",
    "Festő": "FEST", "Burkoló": "BURK", "Gipszkartonos": "GIPSZ", "Asztalos": "ASZT",
  };
  return map[trade] || "SZ";
}

// Egyedi belépési kód generálása egy szakmának (pl. "SZ-VIZ-4827")
function generateTradeCode(trade, existingCodes) {
  let code;
  do {
    const n = Math.floor(1000 + Math.random() * 9000);
    code = `SZ-${tradePrefix(trade)}-${n}`;
  } while (existingCodes.includes(code));
  return code;
}

