/* ── API-kliens ─────────────────────────────────────────────────────
   Minden szerverrel való kommunikáció itt egy helyen. A "credentials:
   same-origin" (alapérték) gondoskodik róla, hogy a session-cookie
   minden kéréssel együtt menjen. Hibánál egységesen dobunk egy Error-t
   a szerver üzenetével, amit a hívó oldal el tud kapni.
─────────────────────────────────────────────────────────────────── */
async function apiCall(url, options = {}) {
  const res = await fetch(url, {
    headers: { "Content-Type": "application/json" },
    ...options,
  });
  const data = await res.json().catch(() => ({}));
  if (!res.ok || data.ok === false) {
    throw new Error(data.error || "Hiba történt a kéréskor.");
  }
  return data;
}

