// Aktuális hibalista PDF — projektre, szakmánként csoportosítva.
// Nyomtatható ablakot nyit; a böngésző "Mentés PDF-ként" funkciójával menthető.
function exportPdf(project, tickets) {
  const byTrade = {};
  tickets.forEach(t => { (byTrade[t.trade] = byTrade[t.trade] || []).push(t); });
  const esc = (s) => String(s ?? "").replace(/[&<>]/g, c => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;" }[c]));
  const today = new Date().toLocaleDateString("hu-HU");

  const sections = Object.keys(byTrade).sort().map(trade => {
    const rows = byTrade[trade].map((t, i) => `
      <tr>
        <td class="num">${i + 1}</td>
        <td>${esc(t.title)}${t.isPrivate ? ' <span class="priv">[belső]</span>' : ""}</td>
        <td>${esc(t.room || "—")}</td>
        <td><span class="badge" style="background:${statusColor(t.status)}">${esc(statusLabel(t.status))}</span></td>
        <td class="notes">${(t.notes || []).length} bejegyzés</td>
      </tr>`).join("");
    return `
      <h2>${esc(trade)} <span class="count">(${byTrade[trade].length} hiba)</span></h2>
      <table>
        <thead><tr><th>#</th><th>Megnevezés</th><th>Helyiség</th><th>Státusz</th><th></th></tr></thead>
        <tbody>${rows}</tbody>
      </table>`;
  }).join("");

  const html = `<!DOCTYPE html><html lang="hu"><head><meta charset="utf-8">
    <title>Hibalista – ${esc(project?.code || "")}</title>
    <style>
      * { font-family: -apple-system, Arial, sans-serif; }
      body { margin: 32px; color: #1a1f29; }
      .head { border-bottom: 3px solid #e6b450; padding-bottom: 14px; margin-bottom: 20px; }
      .logo { font-size: 22px; font-weight: 800; }
      .logo span { color: #d4943a; }
      .meta { color: #667; font-size: 13px; margin-top: 4px; }
      h2 { font-size: 15px; margin: 22px 0 8px; border-left: 4px solid #4dabf7; padding-left: 9px; }
      .count { color: #889; font-weight: 400; font-size: 13px; }
      table { width: 100%; border-collapse: collapse; font-size: 12.5px; }
      th { text-align: left; padding: 6px 8px; border-bottom: 2px solid #dde; color: #667; font-size: 11px; text-transform: uppercase; }
      td { padding: 7px 8px; border-bottom: 1px solid #eef; vertical-align: top; }
      td.num { color: #aab; width: 24px; }
      td.notes { color: #889; white-space: nowrap; }
      .badge { color: #fff; padding: 2px 8px; border-radius: 4px; font-size: 11px; font-weight: 600; }
      .priv { color: #d6336c; font-size: 11px; }
      .footer { margin-top: 28px; color: #99a; font-size: 11px; border-top: 1px solid #eef; padding-top: 10px; }
      @media print { body { margin: 12mm; } }
    </style></head><body>
    <div class="head">
      <div class="logo">Plan<span>Star</span> — Hibalista</div>
      <div class="meta">${esc(project?.name || "")} · ${esc(project?.code || "")} · Generálva: ${today} · Összesen ${tickets.length} hiba</div>
    </div>
    ${sections || "<p>Nincs hibajegy ezen a projekten.</p>"}
    <div class="footer">PlanStar — helyszíni hibakezelő rendszer · A lista az adott pillanat állapotát tükrözi.</div>
    <script>window.onload = () => setTimeout(() => window.print(), 350);<\/script>
    </body></html>`;

  const w = window.open("", "_blank");
  if (w) { w.document.write(html); w.document.close(); }
}



// Egyszerű reszponzív kapcsoló: keskeny képernyőn (telefon) egymás alá rendezünk.
function useIsMobile(breakpoint = 820) {
  const [isMobile, setIsMobile] = useState(
    typeof window !== "undefined" ? window.innerWidth < breakpoint : false
  );
  useEffect(() => {
    const onResize = () => setIsMobile(window.innerWidth < breakpoint);
    window.addEventListener("resize", onResize);
    onResize();
    return () => window.removeEventListener("resize", onResize);
  }, [breakpoint]);
  return isMobile;
}

