/* ═══════════════════════════ FŐ KOMPONENS ═══════════════════════════ */
export default function PlanStar() {
  const [session, setSession] = useState(null);     // a bejelentkezett user (a /api/auth/me válasza)
  const [screen, setScreen] = useState("home");      // belépés előtti nézet: "home" | "login" | "landing"
  const [booting, setBooting] = useState(true);      // induláskor: már lekérdeztük-e a session-t?
  const [projectChoices, setProjectChoices] = useState(null); // ha többfelé léphet be, itt a lista

  // login form
  const [code, setCode] = useState("");
  const [pin, setPin] = useState("");
  const [showPin, setShowPin] = useState(false);
  const [error, setError] = useState("");
  const [loggingIn, setLoggingIn] = useState(false);

  // Induláskor megnézzük, van-e már érvényes session (pl. frissítés után
  // is bejelentkezve maradjon a felhasználó).
  useEffect(() => {
    api.me()
      .then(({ user }) => { if (user) setSession(user); })
      .catch(() => {})
      .finally(() => setBooting(false));
  }, []);

  const handleLogin = async () => {
    setError("");
    if (!code.trim() || !pin.trim()) {
      setError("Add meg az azonosító kódot és a PIN-t.");
      return;
    }
    setLoggingIn(true);
    try {
      const res = await api.login(code.trim(), pin.trim());
      if (res.needsProjectPick) {
        setProjectChoices(res.projects); // a felület projektválasztót mutat
      } else {
        const me = await api.me();
        setSession(me.user);
        setCode(""); setPin("");
      }
    } catch (e) {
      setError(e.message);
    } finally {
      setLoggingIn(false);
    }
  };

  const pickProject = async (projectId) => {
    setError("");
    try {
      await api.selectProject(projectId);
      const me = await api.me();
      setSession(me.user);
      setProjectChoices(null);
      setCode(""); setPin("");
    } catch (e) {
      setError(e.message);
    }
  };

  const logout = async () => {
    try { await api.logout(); } catch {}
    setSession(null);
    setProjectChoices(null);
    setScreen("home");
  };

  // Amíg nem tudjuk, van-e session, ne pislogjon a felület a login képernyőre
  if (booting) {
    return <div style={{ minHeight: "100vh", background: "#0a0e14" }} />;
  }

  if (projectChoices) {
    return <ProjectPicker projects={projectChoices} onPick={pickProject} onCancel={() => setProjectChoices(null)} error={error} />;
  }

  if (!session) {
    if (screen === "home") {
      return <HomeScreen onClient={() => setScreen("login")} onProspect={() => setScreen("landing")} />;
    }
    if (screen === "landing") {
      return <LandingPage onBack={() => setScreen("home")} onLogin={() => setScreen("login")} />;
    }
    return <LoginScreen {...{ code, setCode, pin, setPin, showPin, setShowPin, error, handleLogin, loggingIn, onBack: () => setScreen("home") }} />;
  }
  if (session.role === ROLE.ADMIN) {
    return <AdminConsole session={session} logout={logout} />;
  }
  return <ProjectView session={session} logout={logout} />;
}

/* Projektválasztó — ha a usernek (jellemzően GC-nek) több aktív projektje
   van, belépés után itt választja ki, melyikbe lép. */
function ProjectPicker({ projects, onPick, onCancel, error }) {
  const [q, setQ] = useState("");
  const filtered = projects.filter(p =>
    p.name.toLowerCase().includes(q.toLowerCase()) || p.code.toLowerCase().includes(q.toLowerCase()));

  return (
    <div style={S.loginWrap}>
      <div style={S.grid} />
      <div style={S.loginCard}>
        <button onClick={onCancel} style={S.backLink}>← Vissza</button>
        <div style={{ fontWeight: 700, fontSize: 17, marginBottom: 6, marginTop: 8 }}>Válassz projektet</div>
        <div style={{ fontSize: 13, color: "#8893a3", marginBottom: 18 }}>
          Több futó projekthez is van hozzáférésed. Melyikbe szeretnél belépni?
        </div>
        {error && <div style={S.errorBox}><AlertTriangle size={15} /> <span>{error}</span></div>}
        {projects.length > 3 && (
          <div style={{ position: "relative", marginBottom: 14 }}>
            <Search size={14} style={{ position: "absolute", left: 12, top: 13, color: "#5a6472" }} />
            <input
              style={{ ...S.input, paddingLeft: 34 }}
              placeholder="Keresés projekt neve vagy kódja szerint…"
              value={q}
              onChange={e => setQ(e.target.value)}
              autoFocus
            />
          </div>
        )}
        <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
          {filtered.map(p => (
            <button key={p.projectId} onClick={() => onPick(p.projectId)} style={S.projectPickBtn}>
              <div style={{ textAlign: "left" }}>
                <div style={{ fontWeight: 700, fontSize: 14.5 }}>{p.name}</div>
                <code style={{ color: "#e6b450", fontSize: 12 }}>{p.code}</code>
              </div>
              <span style={{ color: "#5a6472" }}>→</span>
            </button>
          ))}
          {filtered.length === 0 && (
            <div style={{ textAlign: "center", color: "#5a6472", fontSize: 13, padding: "12px 0" }}>
              Nincs a keresésnek megfelelő projekt.
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

