/* Alvállalkozó-meghívó űrlap (GC tölti ki) — cégadatok + ki fizet */
function InviteModal({ session, projectId, onClose, onSubmit }) {
  const [inviteType, setInviteType] = useState("TRADE"); // "TRADE" | "EV"
  const [trade, setTrade] = useState(TRADES[0]);
  const [name, setName] = useState("");
  const [seat, setSeat] = useState("");
  const [taxId, setTaxId] = useState("");
  const [contact, setContact] = useState("");
  const [phone, setPhone] = useState("");
  const [email, setEmail] = useState("");
  const [payer, setPayer] = useState(PAYER.TRADE);
  const [sent, setSent] = useState(false);
  const [evResult, setEvResult] = useState(null); // { pin, code } EV-meghívás után
  const [sending, setSending] = useState(false);
  const [submitError, setSubmitError] = useState("");

  useEffect(() => {
    const onKey = (e) => e.key === "Escape" && onClose();
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, [onClose]);

  const submit = async () => {
    if (!name.trim()) return;
    setSending(true);
    setSubmitError("");
    try {
      if (inviteType === "EV") {
        const res = await api.inviteEv(projectId, {
          name: name.trim(), phone: phone.trim(), email: email.trim(),
        });
        setEvResult(res.user || res);
        setSent(true);
      } else {
        const res = await api.createAccessRequest({
          trade,
          companyName: name.trim(), companySeat: seat.trim(), taxId: taxId.trim(),
          contact: contact.trim(), phone: phone.trim(), email: email.trim(),
          payer: payer === PAYER.GC ? "GC" : "TRADE",
          amount: 15000,
        });
        setSent(true);
        onSubmit(res.accessRequest);
      }
    } catch (e) {
      setSubmitError(e.message);
    } finally {
      setSending(false);
    }
  };

  return (
    <div style={S.modalOverlay} onClick={onClose}>
      <div style={S.modal} onClick={e => e.stopPropagation()}>
        <div style={{ ...S.modalHead, borderTop: `3px solid ${inviteType === "EV" ? "#3bc9db" : "#4dabf7"}` }}>
          <div style={{ flex: 1 }}>
            <div style={{ fontSize: 16, fontWeight: 700, display: "flex", alignItems: "center", gap: 8 }}>
              <Users size={17} color={inviteType === "EV" ? "#3bc9db" : "#4dabf7"} /> {inviteType === "EV" ? "Építésvezető meghívása" : "Alvállalkozó meghívása"}
            </div>
            <div style={{ fontSize: 12.5, color: "#8893a3", marginTop: 4 }}>
              {inviteType === "EV"
                ? `${projectId} projekthez · azonnal létrejön, nincs admin-jóváhagyás`
                : `${projectId} projekthez · a kérés az adminhoz kerül jóváhagyásra`}
            </div>
          </div>
          <button onClick={onClose} style={S.modalClose}><X size={18} /></button>
        </div>

        <div style={S.modalBody}>
          {sent ? (
            inviteType === "EV" ? (
              <div style={{ textAlign: "center", padding: "10px 0" }}>
                <CheckCircle2 size={36} color="#69db7c" style={{ marginBottom: 10 }} />
                <div style={{ fontWeight: 700, fontSize: 15 }}>Építésvezető hozzáadva</div>
                <div style={{ fontSize: 13, color: "#8893a3", marginTop: 6, lineHeight: 1.5 }}>
                  Add át a belépési adatokat <b>{name.trim()}</b> részére. Az EV a generálkivitelezővel azonos jogkörrel lép be.
                </div>
                {evResult && (evResult.code || evResult.pin) && (
                  <div style={{ marginTop: 14, padding: "12px 14px", background: "#161c27", borderRadius: 8, textAlign: "left" }}>
                    {evResult.code && (
                      <div style={{ marginBottom: 8 }}>
                        <div style={{ fontSize: 11, color: "#8893a3", textTransform: "uppercase", letterSpacing: ".3px" }}>Belépési kód</div>
                        <div style={{ fontSize: 16, fontWeight: 700, fontFamily: "monospace", color: "#3bc9db" }}>{evResult.code}</div>
                      </div>
                    )}
                    {evResult.pin && (
                      <div>
                        <div style={{ fontSize: 11, color: "#8893a3", textTransform: "uppercase", letterSpacing: ".3px" }}>PIN</div>
                        <div style={{ fontSize: 16, fontWeight: 700, fontFamily: "monospace", color: "#3bc9db" }}>{evResult.pin}</div>
                      </div>
                    )}
                  </div>
                )}
                <button onClick={onClose} style={{ ...S.primaryBtnSm, marginTop: 16, justifyContent: "center", width: "100%" }}>Bezárás</button>
              </div>
            ) : (
            <div style={{ textAlign: "center", padding: "10px 0" }}>
              <CheckCircle2 size={36} color="#69db7c" style={{ marginBottom: 10 }} />
              <div style={{ fontWeight: 700, fontSize: 15 }}>Kérés elküldve</div>
              <div style={{ fontSize: 13, color: "#8893a3", marginTop: 6, lineHeight: 1.5 }}>
                Az admin jóváhagyja, és a befizetés beérkezése után kiküldi a belépési kódot a megadott elérhetőségre.
              </div>
              <button onClick={onClose} style={{ ...S.primaryBtnSm, marginTop: 16, justifyContent: "center", width: "100%" }}>Bezárás</button>
            </div>
            )
          ) : (
            <>
              <label style={S.miniLabel}>Meghívás típusa</label>
              <div style={{ display: "flex", gap: 8, marginBottom: 14 }}>
                <button onClick={() => setInviteType("TRADE")}
                  style={{ ...S.payerBtn, ...(inviteType === "TRADE" ? S.payerBtnOn : {}) }}>
                  Alvállalkozó
                </button>
                <button onClick={() => setInviteType("EV")}
                  style={{ ...S.payerBtn, ...(inviteType === "EV" ? S.payerBtnOn : {}) }}>
                  Építésvezető
                </button>
              </div>

              {inviteType === "TRADE" && (
                <>
                  <label style={S.miniLabel}>Szakma</label>
                  <select style={{ ...S.input, marginBottom: 12, cursor: "pointer" }} value={trade} onChange={e => setTrade(e.target.value)}>
                    {TRADES.map(t => <option key={t} value={t}>{t}</option>)}
                  </select>
                </>
              )}

              <label style={S.miniLabel}>{inviteType === "EV" ? "Név" : "Cégnév"}</label>
              <input autoFocus style={{ ...S.input, marginBottom: 12 }} placeholder={inviteType === "EV" ? "pl. Nagy Péter" : "pl. Csőmester Bt."} value={name} onChange={e => setName(e.target.value)} />

              {inviteType === "TRADE" && (
                <>
                  <label style={S.miniLabel}>Székhely</label>
                  <input style={{ ...S.input, marginBottom: 12 }} placeholder="irányítószám, település, utca" value={seat} onChange={e => setSeat(e.target.value)} />

                  <div style={{ display: "flex", gap: 10 }}>
                    <div style={{ flex: 1 }}>
                      <label style={S.miniLabel}>Adószám</label>
                      <input style={{ ...S.input, marginBottom: 12 }} placeholder="________-_-__" value={taxId} onChange={e => setTaxId(e.target.value)} />
                    </div>
                    <div style={{ flex: 1 }}>
                      <label style={S.miniLabel}>Kapcsolattartó</label>
                      <input style={{ ...S.input, marginBottom: 12 }} placeholder="név" value={contact} onChange={e => setContact(e.target.value)} />
                    </div>
                  </div>
                </>
              )}

              <div style={{ display: "flex", gap: 10 }}>
                <div style={{ flex: 1 }}>
                  <label style={S.miniLabel}>Telefon</label>
                  <input style={{ ...S.input, marginBottom: 12 }} placeholder="+36 ..." value={phone} onChange={e => setPhone(e.target.value)} />
                </div>
                <div style={{ flex: 1 }}>
                  <label style={S.miniLabel}>E-mail</label>
                  <input style={{ ...S.input, marginBottom: 12 }} placeholder="@" value={email} onChange={e => setEmail(e.target.value)} />
                </div>
              </div>

              {inviteType === "TRADE" && (
                <>
                  <label style={S.miniLabel}>Ki fizeti a hozzáférést?</label>
                  <div style={{ display: "flex", gap: 8, marginBottom: 8 }}>
                    <button onClick={() => setPayer(PAYER.TRADE)}
                      style={{ ...S.payerBtn, ...(payer === PAYER.TRADE ? S.payerBtnOn : {}) }}>
                      Az alvállalkozó
                    </button>
                    <button onClick={() => setPayer(PAYER.GC)}
                      style={{ ...S.payerBtn, ...(payer === PAYER.GC ? S.payerBtnOn : {}) }}>
                      Én (GC)
                    </button>
                  </div>
                </>
              )}

              {submitError && <div style={S.errorBox}><AlertTriangle size={15} /> <span>{submitError}</span></div>}
              <button onClick={submit} disabled={sending} style={{ ...S.primaryBtn, marginTop: 8, opacity: sending ? 0.7 : 1 }}>
                <Users size={16} /> {sending ? "Küldés…" : (inviteType === "EV" ? "Építésvezető hozzáadása" : "Meghívás elküldése")}
              </button>
            </>
          )}
        </div>
      </div>
    </div>
  );
}

/* Takarítás-kérő űrlap — fotóval és az érintett szakmák megjelölésével.
   Egy "Takarítás" kategóriájú hibajegyet hoz létre. */
function CleaningForm({ draft, presentTrades, onCancel, onSave }) {
  const [desc, setDesc] = useState("");
  const [room, setRoom] = useState("");
  const [selectedTrades, setSelectedTrades] = useState([]);
  const [img, setImg] = useState(null);
  const fileRef = React.useRef(null);

  const toggle = (t) => setSelectedTrades(s => s.includes(t) ? s.filter(x => x !== t) : [...s, t]);

  const onPick = (e) => {
    const file = e.target.files?.[0]; if (!file) return;
    const reader = new FileReader();
    reader.onload = () => {
      const im = new Image();
      im.onload = () => {
        const maxW = 1200, scale = Math.min(1, maxW / im.width);
        const c = document.createElement("canvas");
        c.width = im.width * scale; c.height = im.height * scale;
        c.getContext("2d").drawImage(im, 0, 0, c.width, c.height);
        setImg(c.toDataURL("image/jpeg", 0.8));
      };
      im.src = reader.result;
    };
    reader.readAsDataURL(file);
    e.target.value = "";
  };

  const save = () => {
    const who = selectedTrades.length ? selectedTrades.join(", ") : "általános";
    const note = {
      author: "Generálkivitelező", role: ROLE.GC,
      time: new Date().toISOString().slice(0, 16).replace("T", " "),
      text: `Takarítás kérése — érintett: ${who}.${desc ? " " + desc : ""}`,
      image: img || null,
    };
    onSave({
      title: desc.trim() ? `Takarítás: ${desc.trim()}` : "Takarítás kérése",
      trade: "Takarítás", room: room.trim(), private: false,
      cleaningFor: selectedTrades, notes: [note],
    });
  };

  return (
    <div style={{ ...S.newForm, borderColor: "#69db7c55" }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}>
        <span style={{ fontWeight: 700, display: "inline-flex", alignItems: "center", gap: 6 }}>
          <Sparkles size={15} color="#69db7c" /> Takarítást kérek
        </span>
        <span style={{ fontSize: 11, color: "#5a6472", fontFamily: mono }}>{draft.x}% · {draft.y}%</span>
      </div>

      <label style={S.miniLabel}>Mit kell takarítani? (opcionális)</label>
      <input autoFocus style={{ ...S.input, marginBottom: 12 }} placeholder="pl. törmelék a folyosón"
        value={desc} onChange={e => setDesc(e.target.value)} />

      <label style={S.miniLabel}>Helyiség (opcionális)</label>
      <input style={{ ...S.input, marginBottom: 12 }} placeholder="pl. A lakás · nappali"
        value={room} onChange={e => setRoom(e.target.value)} />

      <label style={S.miniLabel}>Kiket érint? (akik a kupit hagyták)</label>
      <div style={{ display: "flex", gap: 6, flexWrap: "wrap", marginBottom: 12 }}>
        {presentTrades.map(t => {
          const on = selectedTrades.includes(t);
          return (
            <button key={t} onClick={() => toggle(t)}
              style={{ ...S.filterChip, ...(on ? { background: "#69db7c", border: "1px solid #69db7c", color: "#0a0e14" } : {}) }}>
              {on ? "✓ " : ""}{t}
            </button>
          );
        })}
      </div>

      <input ref={fileRef} type="file" accept="image/*" capture="environment" onChange={onPick} style={{ display: "none" }} />
      {img ? (
        <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 12 }}>
          <img src={img} alt="" style={{ width: 56, height: 56, objectFit: "cover", borderRadius: 7 }} />
          <button onClick={() => setImg(null)} style={S.cancelBtn}>Kép törlése</button>
        </div>
      ) : (
        <button onClick={() => fileRef.current?.click()} style={{ ...S.placeToggle, width: "100%", justifyContent: "center", marginBottom: 12 }}>
          <ImageIcon size={15} /> Fotó csatolása
        </button>
      )}

      <div style={{ display: "flex", gap: 8 }}>
        <button onClick={save} style={{ ...S.primaryBtnSm, flex: 1, justifyContent: "center", background: "#69db7c" }}>
          <CheckCircle2 size={15} /> Takarítás kérése
        </button>
        <button onClick={onCancel} style={S.cancelBtn}>Mégse</button>
      </div>
    </div>
  );
}

/* Lehelyező űrlap — itt dől el a szakma-tegelés (ki fogja látni) */
function NewTicketForm({ draft, onCancel, onSave }) {
  const [title, setTitle] = useState("");
  const [trade, setTrade] = useState(TRADES[0]);
  const [room, setRoom] = useState("");
  const [priv, setPriv] = useState(false);

  const save = () => {
    if (!title.trim()) return;
    onSave({ title: title.trim(), trade, room: room.trim(), private: priv });
  };

  return (
    <div style={S.newForm}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}>
        <span style={{ fontWeight: 700, display: "inline-flex", alignItems: "center", gap: 6 }}>
          <MapPin size={15} color="#e6b450" /> Új hibajegy
        </span>
        <span style={{ fontSize: 11, color: "#5a6472", fontFamily: mono }}>
          {draft.x}% · {draft.y}%
        </span>
      </div>

      <label style={S.miniLabel}>Megnevezés</label>
      <input autoFocus style={{ ...S.input, marginBottom: 12 }} placeholder="pl. Hiányzó dugalj"
        value={title} onChange={e => setTitle(e.target.value)}
        onKeyDown={e => e.key === "Enter" && save()} />

      <label style={S.miniLabel}>Felelős szakma (tegelés)</label>
      <select style={{ ...S.input, marginBottom: 12, cursor: "pointer" }}
        value={trade} onChange={e => setTrade(e.target.value)}>
        {TRADES.map(t => <option key={t} value={t}>{t}</option>)}
      </select>

      <label style={S.miniLabel}>Helyiség (opcionális)</label>
      <input style={{ ...S.input, marginBottom: 12 }} placeholder="pl. A lakás · konyha"
        value={room} onChange={e => setRoom(e.target.value)} />

      <label style={S.privToggle} onClick={() => setPriv(p => !p)}>
        <span style={{ ...S.checkbox, ...(priv ? S.checkboxOn : {}) }}>
          {priv && <Lock size={11} color="#0a0e14" />}
        </span>
        <span style={{ fontSize: 12.5 }}>Privát / belső — csak GC és a tegelt szakma látja</span>
      </label>

      <div style={{ display: "flex", gap: 8, marginTop: 14 }}>
        <button onClick={save} style={{ ...S.primaryBtnSm, flex: 1, justifyContent: "center" }}>
          <CheckCircle2 size={15} /> Lehelyezés
        </button>
        <button onClick={onCancel} style={S.cancelBtn}>Mégse</button>
      </div>
    </div>
  );
}

/* Gyors státusz-összesítő sáv */
function StatBar({ tickets }) {
  const counts = STATUS_FLOW.map(s => ({ s, n: tickets.filter(t => statusLabel(t.status) === s).length }));
  const total = tickets.length;
  return (
    <div style={S.statBar}>
      <div style={{ display: "flex", gap: 18, flexWrap: "wrap", alignItems: "center" }}>
        <div style={{ fontSize: 13, color: "#7a8499" }}>
          Összesen <b style={{ color: "#e8edf4" }}>{total}</b> hibajegy
        </div>
        {counts.map(({ s, n }) => (
          <div key={s} style={{ display: "inline-flex", alignItems: "center", gap: 6, fontSize: 13 }}>
            <span style={{ width: 9, height: 9, borderRadius: "50%", background: statusColor(s) }} />
            <span style={{ color: "#8893a3" }}>{s}</span>
            <b style={{ color: "#e8edf4" }}>{n}</b>
          </div>
        ))}
      </div>
      {/* Vékony arány-csík */}
      <div style={{ display: "flex", height: 5, borderRadius: 3, overflow: "hidden", marginTop: 10, background: "#141a26" }}>
        {counts.map(({ s, n }) => n > 0 && (
          <div key={s} style={{ width: `${(n / total) * 100}%`, background: statusColor(s) }} />
        ))}
      </div>
    </div>
  );
}

/* Felugró ablak: hibajegy részletei + bejegyzés-szál (pl. az építésvezető írása) */
function TicketModal({ ticket, session, seeComm, canEdit, onUpdated, users, onClose }) {
  const [text, setText] = useState("");
  const [pendingImg, setPendingImg] = useState(null); // csatolásra váró kép (data URL, feltöltés előtt)
  const [lightbox, setLightbox] = useState(null);       // nagyban megnyitott kép
  const [sendingNote, setSendingNote] = useState(false);
  const [noteError, setNoteError] = useState("");
  const fileRef = React.useRef(null);

  // ESC-re bezár (előbb a lightboxot, ha nyitva)
  useEffect(() => {
    const onKey = (e) => {
      if (e.key !== "Escape") return;
      if (lightbox) setLightbox(null); else onClose();
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, [onClose, lightbox]);

  const accent = ticket.isPrivate ? "#ff6b6b" : statusColor(ticket.status);
  const notes = ticket.notes || [];

  const setStatus = async (label) => {
    const dbStatus = STATUS_LABEL_TO_DB[label] || label;
    try {
      const res = await api.updateTicket(session.projectId, ticket.id, { status: dbStatus });
      onUpdated(res.ticket);
    } catch (e) {
      setNoteError(e.message);
    }
  };

  // Kép kiválasztása → méretre csökkentés (hogy ne hízzon el a feltöltés), majd data URL
  const onPickImage = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = () => {
      const img = new Image();
      img.onload = () => {
        const maxW = 1200;
        const scale = Math.min(1, maxW / img.width);
        const canvas = document.createElement("canvas");
        canvas.width = img.width * scale;
        canvas.height = img.height * scale;
        canvas.getContext("2d").drawImage(img, 0, 0, canvas.width, canvas.height);
        setPendingImg(canvas.toDataURL("image/jpeg", 0.8));
      };
      img.src = reader.result;
    };
    reader.readAsDataURL(file);
    e.target.value = ""; // hogy ugyanazt a fájlt újra ki lehessen választani
  };

  const sendNote = async () => {
    if (!text.trim() && !pendingImg) return; // kép önmagában is mehet
    setSendingNote(true);
    setNoteError("");
    try {
      let imageUrl = null;
      if (pendingImg) {
        imageUrl = await api.uploadImage(pendingImg);
      }
      const res = await api.addNote(session.projectId, ticket.id, { text: text.trim() || null, imageUrl });
      onUpdated({ ...ticket, notes: [...notes, res.note] });
      setText("");
      setPendingImg(null);
    } catch (e) {
      setNoteError(e.message);
    } finally {
      setSendingNote(false);
    }
  };

  return (
    <div style={S.modalOverlay} onClick={onClose}>
      <div style={S.modal} onClick={(e) => e.stopPropagation()}>
        {/* Fejléc */}
        <div style={{ ...S.modalHead, borderTop: `3px solid ${accent}` }}>
          <div style={{ flex: 1, minWidth: 0 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 6, flexWrap: "wrap" }}>
              <Pill color="#4dabf7">{ticket.trade}</Pill>
              <Pill color={statusColor(ticket.status)}>{statusLabel(ticket.status)}</Pill>
              {ticket.isPrivate && (
                <span style={{ display: "inline-flex", alignItems: "center", gap: 4, color: "#ff6b6b", fontSize: 11, fontWeight: 600 }}>
                  <Lock size={11} /> Privát
                </span>
              )}
            </div>
            <div style={{ fontSize: 17, fontWeight: 700, lineHeight: 1.3 }}>{ticket.title}</div>
            {ticket.room && <div style={{ fontSize: 12.5, color: "#7a8499", marginTop: 4 }}>📍 {ticket.room}</div>}
          </div>
          <button onClick={onClose} style={S.modalClose} aria-label="Bezárás"><X size={18} /></button>
        </div>

        <div style={S.modalBody}>
          {/* Státuszváltó gombsor — csak GC/Admin/szakma állíthatja */}
          {canEdit && (
            <div style={{ marginBottom: 18 }}>
              <div style={{ fontSize: 11, color: "#7a8499", marginBottom: 8, fontWeight: 600, textTransform: "uppercase", letterSpacing: ".5px" }}>Státusz</div>
              <div style={{ display: "flex", gap: 6, flexWrap: "wrap" }}>
                {STATUS_FLOW.map(s => {
                  const active = statusLabel(ticket.status) === s;
                  const c = statusColor(s);
                  return (
                    <button key={s} onClick={() => setStatus(s)}
                      style={{
                        ...S.statusBtn,
                        ...(active ? { background: c, color: "#0a0e14", borderColor: c } : { color: c, borderColor: `${c}50` }),
                      }}>
                      {s}
                    </button>
                  );
                })}
              </div>
            </div>
          )}

          {/* Bejegyzések / kommunikáció */}
          {!seeComm ? (
            <div style={{ ...S.commBox, color: "#5a6472", fontSize: 12.5, display: "flex", gap: 8, marginTop: 0 }}>
              <EyeOff size={15} style={{ flexShrink: 0 }} /> A részletes bejegyzések a beruházói nézetben nem elérhetők. Itt csak az általános státusz látható.
            </div>
          ) : (
            <>
              <div style={{ fontSize: 12, fontWeight: 600, color: "#7a8499", marginBottom: 10, display: "flex", alignItems: "center", gap: 6 }}>
                <MessageSquare size={14} color="#4dabf7" /> Bejegyzések ({notes.length})
              </div>
              {notes.length === 0 ? (
                <div style={{ color: "#5a6472", fontSize: 13, padding: "4px 0 8px" }}>Még nincs bejegyzés. Írd meg az elsőt lent.</div>
              ) : (
                <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
                  {notes.map((n, i) => {
                    const m = ROLE_META[n.authorRole] || ROLE_META.GC;
                    const Icon = m.icon;
                    return (
                      <div key={n.id || i} style={S.noteCard}>
                        <div style={{ display: "flex", alignItems: "center", gap: 7, marginBottom: 5 }}>
                          <span style={{ display: "inline-flex", alignItems: "center", justifyContent: "center", width: 22, height: 22, borderRadius: 6, background: `${m.color}1a`, color: m.color, flexShrink: 0 }}>
                            <Icon size={13} />
                          </span>
                          <span style={{ fontWeight: 600, fontSize: 13 }}>{n.authorName}</span>
                          {(() => {
                            const u = (users || []).find(x => x.name === n.authorName);
                            return u?.phone ? (
                              <a href={`tel:${u.phone.replace(/\s/g, "")}`} style={S.callBtn} title={`Hívás: ${u.phone}`} onClick={e => e.stopPropagation()}>
                                <Phone size={13} />
                              </a>
                            ) : null;
                          })()}
                          <span style={{ fontSize: 11, color: "#5a6472", marginLeft: "auto", fontFamily: mono }}>{new Date(n.createdAt).toLocaleString("hu-HU")}</span>
                        </div>
                        {n.text && <div style={{ fontSize: 13, color: "#cdd6e3", lineHeight: 1.55 }}>{n.text}</div>}
                        {n.imageUrl && (
                          <img src={n.imageUrl} alt="csatolt kép" onClick={() => setLightbox(n.imageUrl)}
                            style={S.noteThumb} />
                        )}
                      </div>
                    );
                  })}
                </div>
              )}

              {/* Csatolásra váró kép előnézete */}
              {pendingImg && (
                <div style={S.pendingImgWrap}>
                  <img src={pendingImg} alt="előnézet" style={{ width: 56, height: 56, objectFit: "cover", borderRadius: 7 }} />
                  <span style={{ fontSize: 12.5, color: "#8893a3", flex: 1 }}>Kép csatolva — küldéskor a bejegyzéshez kerül.</span>
                  <button onClick={() => setPendingImg(null)} style={S.modalClose} aria-label="Kép eltávolítása"><X size={15} /></button>
                </div>
              )}

              {/* Új bejegyzés — szöveg és/vagy kép */}
              <input ref={fileRef} type="file" accept="image/*" capture="environment"
                onChange={onPickImage} style={{ display: "none" }} />
              {noteError && <div style={S.errorBox}><AlertTriangle size={15} /> <span>{noteError}</span></div>}
              <div style={{ marginTop: 14, display: "flex", gap: 8 }}>
                <button onClick={() => fileRef.current?.click()} style={S.imgBtn} title="Kép csatolása / fotózás">
                  <ImageIcon size={17} />
                </button>
                <input style={{ ...S.input, flex: 1 }} placeholder="Írj bejegyzést…"
                  value={text} onChange={e => setText(e.target.value)}
                  onKeyDown={e => e.key === "Enter" && sendNote()} />
                <button onClick={sendNote} disabled={sendingNote || !(text.trim() || pendingImg)}
                  style={{ ...S.primaryBtnSm, opacity: (text.trim() || pendingImg) && !sendingNote ? 1 : 0.5, cursor: (text.trim() || pendingImg) && !sendingNote ? "pointer" : "not-allowed" }}>
                  {sendingNote ? "Küldés…" : "Küldés"}
                </button>
              </div>
              <div style={{ fontSize: 11, color: "#5a6472", marginTop: 6 }}>
                {session.name} néven írsz. A 📷 gombbal a helyszínen fotózhatsz vagy képet választhatsz.
              </div>
            </>
          )}
        </div>
      </div>

      {/* Kép nagyban */}
      {lightbox && (
        <div style={S.lightbox} onClick={() => setLightbox(null)}>
          <img src={lightbox} alt="csatolt kép nagyban" style={{ maxWidth: "92%", maxHeight: "88%", borderRadius: 10, boxShadow: "0 12px 48px #000" }} />
          <button onClick={() => setLightbox(null)} style={{ ...S.modalClose, position: "absolute", top: 20, right: 20 }}><X size={18} /></button>
        </div>
      )}
    </div>
  );
}

/* ───────────────────────── KÖZÖS ELEMEK ─────────────────────────── */
function TopBar({ session, logout }) {
  return (
    <div style={S.topBar}>
      <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
        <div style={S.logoMarkSm}><MapPin size={16} color="#0a0e14" /></div>
        <span style={{ fontWeight: 800, fontSize: 16 }}>Plan<span style={{ color: "#e6b450" }}>Star</span></span>
        <span style={S.envChip}>DEMO</span>
      </div>
      <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
        <div style={{ textAlign: "right", lineHeight: 1.3 }}>
          <div style={{ fontSize: 13, fontWeight: 600 }}>{session.name}</div>
          <div style={{ fontSize: 11 }}><RoleBadge role={session.role} /></div>
        </div>
        <button onClick={logout} style={S.logoutBtn}><LogOut size={15} /> Kilépés</button>
      </div>
    </div>
  );
}

const Field = ({ label, icon: Icon, children }) => (
  <div style={{ marginBottom: 16 }}>
    <label style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 12, color: "#7a8499", marginBottom: 7, fontWeight: 500 }}>
      <Icon size={13} /> {label}
    </label>
    {children}
  </div>
);
const TabBtn = ({ active, onClick, icon: Icon, children }) => (
  <button onClick={onClick} style={{ ...S.tabBtn, ...(active ? S.tabBtnActive : {}) }}>
    <Icon size={15} /> {children}
  </button>
);
const Legend = ({ c, t }) => (
  <span style={{ display: "inline-flex", alignItems: "center", gap: 6 }}>
    <span style={{ width: 9, height: 9, borderRadius: "50%", background: c }} /> {t}
  </span>
);

